def _set_bot(bot_id, prompt):
    op.execute(_BOTS.update().where(_BOTS.c.bot_id == op.inline_literal(bot_id)).values(system_prompt=prompt))


def _set_condense(code, content):
    op.execute(
        _LP.update()
        .where(sa.and_(_LP.c.prompt_key == op.inline_literal("condense"), _LP.c.code == op.inline_literal(code)))
        .values(content=content)
    )


